import java.util.concurrent.*;
public class CompletableFutureDemo {
    public static void main(String[] args) throws Exception {
        CompletableFuture<Integer> cf = CompletableFuture
            .supplyAsync(() -> 10)
            .thenApply(n -> n * 2)
            .thenApply(n -> n + 5);
        System.out.println(cf.get());
    }
}
